   150→// ViaHTTP scans servers by HTTP header and body
   151→func ViaHTTP(header http.Header, body string, toLocalFile bool) (models.ScanResult, error) {
   152→	family := header.Get("X-Vuls-OS-Family")
   153→	if family == "" {
   154→		return models.ScanResult{}, errOSFamilyHeader
   155→	}
   156→
   157→	release := header.Get("X-Vuls-OS-Release")
   158→	if release == "" {
   159→		return models.ScanResult{}, errOSReleaseHeader
   160→	}
   161→
   162→	kernelRelease := header.Get("X-Vuls-Kernel-Release")
   163→	if kernelRelease == "" {
   164→		logging.Log.Warn("If X-Vuls-Kernel-Release is not specified, there is a possibility of false detection")
   165→	}
   166→
   167→	kernelVersion := header.Get("X-Vuls-Kernel-Version")
   168→	if family == constant.Debian {
   169→		if kernelVersion == "" {
   170→			logging.Log.Warn("X-Vuls-Kernel-Version is empty. skip kernel vulnerability detection.")
   171→		} else {
   172→			if _, err := debver.NewVersion(kernelVersion); err != nil {
   173→				logging.Log.Warnf("X-Vuls-Kernel-Version is invalid. skip kernel vulnerability detection. actual kernelVersion: %s, err: %s", kernelVersion, err)
   174→				kernelVersion = ""
   175→			}
   176→		}
   177→	}
   178→
   179→	serverName := header.Get("X-Vuls-Server-Name")
   180→	if toLocalFile && serverName == "" {
   181→		return models.ScanResult{}, errServerNameHeader
   182→	}
   183→
   184→	distro := config.Distro{
   185→		Family:  family,
   186→		Release: release,
   187→	}
   188→
   189→	kernel := models.Kernel{
   190→		Release: kernelRelease,
   191→		Version: kernelVersion,
   192→	}
   193→	installedPackages, srcPackages, err := ParseInstalledPkgs(distro, kernel, body)
   194→	if err != nil {
   195→		return models.ScanResult{}, err
   196→	}
   197→
   198→	return models.ScanResult{
   199→		ServerName: serverName,
   200→		Family:     family,
   201→		Release:    release,
   202→		RunningKernel: models.Kernel{
   203→			Release: kernelRelease,
   204→			Version: kernelVersion,
   205→		},
   206→		Packages:    installedPackages,
   207→		SrcPackages: srcPackages,
   208→		ScannedCves: models.VulnInfos{},
   209→	}, nil
   210→}
   211→
   212→// ParseInstalledPkgs parses installed pkgs line
   213→func ParseInstalledPkgs(distro config.Distro, kernel models.Kernel, pkgList string) (models.Packages, models.SrcPackages, error) {
   214→	base := base{
   215→		Distro: distro,
   216→		osPackages: osPackages{
   217→			Kernel: kernel,
   218→		},
   219→		log: logging.Log,
   220→	}
   221→
   222→	var osType osTypeInterface
   223→	switch distro.Family {
   224→	case constant.Debian, constant.Ubuntu, constant.Raspbian:
   225→		osType = &debian{base: base}
   226→	case constant.RedHat:
   227→		osType = &rhel{redhatBase: redhatBase{base: base}}
   228→	case constant.CentOS:
   229→		osType = &centos{redhatBase: redhatBase{base: base}}
   230→	case constant.Alma:
   231→		osType = &alma{redhatBase: redhatBase{base: base}}
   232→	case constant.Rocky:
   233→		osType = &rocky{redhatBase: redhatBase{base: base}}
   234→	case constant.Oracle:
   235→		osType = &oracle{redhatBase: redhatBase{base: base}}
   236→	case constant.Amazon:
   237→		osType = &amazon{redhatBase: redhatBase{base: base}}
   238→	case constant.Fedora:
   239→		osType = &fedora{redhatBase: redhatBase{base: base}}
   240→	case constant.OpenSUSE, constant.OpenSUSELeap, constant.SUSEEnterpriseServer, constant.SUSEEnterpriseDesktop:
   241→		osType = &suse{redhatBase: redhatBase{base: base}}
   242→	default:
   243→		return models.Packages{}, models.SrcPackages{}, xerrors.Errorf("Server mode for %s is not implemented yet", base.Distro.Family)
   244→	}
   245→
   246→	return osType.parseInstalledPackages(pkgList)
   247→}
