   512→func parseSSHScan(stdout string) map[string]string {
   513→	keys := map[string]string{}
   514→	for _, line := range strings.Split(stdout, "\n") {
   515→		if line == "" || strings.HasPrefix(line, "# ") {
   516→			continue
   517→		}
   518→		if ss := strings.Split(line, " "); len(ss) == 3 {
   519→			keys[ss[1]] = ss[2]
   520→		}
   521→	}
   522→	return keys
   523→}
   524→
   525→func parseSSHKeygen(stdout string) (string, string, error) {
   526→	for _, line := range strings.Split(stdout, "\n") {
   527→		if line == "" || strings.HasPrefix(line, "# ") {
   528→			continue
   529→		}
   530→
   531→		// HashKnownHosts yes
   532→		if strings.HasPrefix(line, "|1|") {
   533→			ss := strings.Split(line, "|")
   534→			if ss := strings.Split(ss[len(ss)-1], " "); len(ss) == 3 {
   535→				return ss[1], ss[2], nil
   536→			}
   537→		} else {
   538→			if ss := strings.Split(line, " "); len(ss) == 3 {
   539→				return ss[1], ss[2], nil
   540→			}
   541→		}
   542→	}
   543→	return "", "", xerrors.New("Failed to parse ssh-keygen result. err: public key not found")
   544→}
