   667→func (s Scanner) detectOS(c config.ServerInfo) osTypeInterface {
   668→	if itsMe, osType, _ := detectPseudo(c); itsMe {
   669→		return osType
   670→	}
   671→
   672→	if itsMe, osType, fatalErr := s.detectDebianWithRetry(c); fatalErr != nil {
   673→		osType.setErrs([]error{xerrors.Errorf("Failed to detect OS: %w", fatalErr)})
   674→		return osType
   675→	} else if itsMe {
   676→		logging.Log.Debugf("Debian based Linux. Host: %s:%s", c.Host, c.Port)
   677→		return osType
   678→	}
   679→
   680→	if itsMe, osType := detectRedhat(c); itsMe {
   681→		logging.Log.Debugf("Redhat based Linux. Host: %s:%s", c.Host, c.Port)
   682→		return osType
   683→	}
   684→
   685→	if itsMe, osType := detectSUSE(c); itsMe {
   686→		logging.Log.Debugf("SUSE Linux. Host: %s:%s", c.Host, c.Port)
   687→		return osType
   688→	}
   689→
   690→	if itsMe, osType := detectFreebsd(c); itsMe {
   691→		logging.Log.Debugf("FreeBSD. Host: %s:%s", c.Host, c.Port)
   692→		return osType
   693→	}
   694→
   695→	if itsMe, osType := detectAlpine(c); itsMe {
   696→		logging.Log.Debugf("Alpine. Host: %s:%s", c.Host, c.Port)
   697→		return osType
   698→	}
   699→
   700→	osType := &unknown{base{ServerInfo: c}}
   701→	osType.setErrs([]error{xerrors.New("Unknown OS Type")})
   702→	return osType
   703→}
