   803→// execScan scan
   804→func (s Scanner) execScan() error {
   805→	if len(servers) == 0 {
   806→		return xerrors.New("No server defined. Check the configuration")
   807→	}
   808→
   809→	if err := s.setupChangelogCache(); err != nil {
   810→		return err
   811→	}
   812→	defer func() {
   813→		if cache.DB != nil {
   814→			cache.DB.Close()
   815→		}
   816→	}()
   817→
   818→	scannedAt := time.Now()
   819→	dir, err := EnsureResultDir(s.ResultsDir, scannedAt)
   820→	if err != nil {
   821→		return err
   822→	}
   823→
   824→	results, err := s.getScanResults(scannedAt)
   825→	if err != nil {
   826→		return err
   827→	}
   828→
   829→	for i, r := range results {
   830→		if server, ok := s.Targets[r.ServerName]; ok {
   831→			results[i] = r.ClearFields(server.IgnoredJSONKeys)
   832→		}
   833→	}
   834→
   835→	return writeScanResults(dir, results)
   836→}
