   861→// getScanResults returns ScanResults
   862→func (s Scanner) getScanResults(scannedAt time.Time) (results models.ScanResults, err error) {
   863→	parallelExec(func(o osTypeInterface) (err error) {
   864→		if o.getServerInfo().Module.IsScanOSPkg() {
   865→			if err = o.preCure(); err != nil {
   866→				return err
   867→			}
   868→			if err = o.scanPackages(); err != nil {
   869→				return err
   870→			}
   871→			if err = o.postScan(); err != nil {
   872→				return err
   873→			}
   874→		}
   875→		if o.getServerInfo().Module.IsScanPort() {
   876→			if err = o.scanPorts(); err != nil {
   877→				// continue scanning
   878→				logging.Log.Warnf("Failed to scan Ports: %+v", err)
   879→			}
   880→		}
   881→		if o.getServerInfo().Module.IsScanWordPress() {
   882→			if err = o.scanWordPress(); err != nil {
   883→				return xerrors.Errorf("Failed to scan WordPress: %w", err)
   884→			}
   885→		}
   886→		if o.getServerInfo().Module.IsScanLockFile() {
   887→			if err = o.scanLibraries(); err != nil {
   888→				return xerrors.Errorf("Failed to scan Library: %w", err)
   889→			}
   890→		}
   891→		return nil
   892→	}, s.ScanTimeoutSec)
   893→
   894→	hostname, _ := os.Hostname()
   895→	ipv4s, ipv6s, err := util.IP()
   896→	if err != nil {
   897→		logging.Log.Warnf("Failed to get scannedIPs. err: %+v", err)
   898→	}
   899→
   900→	for _, s := range append(servers, errServers...) {
   901→		r := s.convertToModel()
   902→		r.CheckEOL()
   903→		r.ScannedAt = scannedAt
   904→		r.ScannedVersion = config.Version
   905→		r.ScannedRevision = config.Revision
   906→		r.ScannedBy = hostname
   907→		r.ScannedIPv4Addrs = ipv4s
   908→		r.ScannedIPv6Addrs = ipv6s
   909→		r.Config.Scan = config.Conf
   910→		results = append(results, r)
   911→
   912→		if 0 < len(r.Warnings) {
   913→			logging.Log.Warnf("Some warnings occurred during scanning on %s. Please fix the warnings to get a useful information. Execute configtest subcommand before scanning to know the cause of the warnings. warnings: %v",
   914→				r.ServerName, r.Warnings)
   915→		}
   916→	}
   917→	return results, nil
   918→}
