   282→func (s Scanner) detectServerOSes() (servers, errServers []osTypeInterface) {
   283→	logging.Log.Info("Detecting OS of servers... ")
   284→	osTypeChan := make(chan osTypeInterface, len(s.Targets))
   285→	defer close(osTypeChan)
   286→	for _, target := range s.Targets {
   287→		go func(srv config.ServerInfo) {
   288→			defer func() {
   289→				if p := recover(); p != nil {
   290→					logging.Log.Debugf("Panic: %s on %s", p, srv.ServerName)
   291→				}
   292→			}()
   293→			if err := validateSSHConfig(&srv); err != nil {
   294→				checkOS := unknown{base{ServerInfo: srv}}
   295→				checkOS.setErrs([]error{err})
   296→				osTypeChan <- &checkOS
   297→				return
   298→			}
   299→			osTypeChan <- s.detectOS(srv)
   300→		}(target)
   301→	}
   302→
   303→	timeout := time.After(time.Duration(s.TimeoutSec) * time.Second)
   304→	for i := 0; i < len(s.Targets); i++ {
   305→		select {
   306→		case res := <-osTypeChan:
   307→			if 0 < len(res.getErrs()) {
   308→				errServers = append(errServers, res)
   309→				logging.Log.Errorf("(%d/%d) Failed: %s, err: %+v", i+1, len(s.Targets), res.getServerInfo().ServerName, res.getErrs())
   310→			} else {
   311→				servers = append(servers, res)
   312→				logging.Log.Infof("(%d/%d) Detected: %s: %s", i+1, len(s.Targets), res.getServerInfo().ServerName, res.getDistro())
   313→			}
   314→		case <-timeout:
   315→			msg := "Timed out while detecting servers"
   316→			logging.Log.Error(msg)
   317→			for servername, sInfo := range s.Targets {
   318→				found := false
   319→				for _, o := range append(servers, errServers...) {
   320→					if servername == o.getServerInfo().ServerName {
   321→						found = true
   322→						break
   323→					}
   324→				}
   325→				if !found {
   326→					u := &unknown{}
   327→					u.setServerInfo(sInfo)
   328→					u.setErrs([]error{xerrors.New("Timed out")})
   329→					errServers = append(errServers, u)
   330→					logging.Log.Errorf("(%d/%d) Timed out: %s", i+1, len(s.Targets), servername)
   331→				}
   332→			}
   333→		}
   334→	}
   335→	return
   336→}
