   338→func validateSSHConfig(c *config.ServerInfo) error {
   339→	if isLocalExec(c.Port, c.Host) || c.Type == constant.ServerTypePseudo {
   340→		return nil
   341→	}
   342→
   343→	logging.Log.Debugf("Validating SSH Settings for Server:%s ...", c.GetServerName())
   344→
   345→	sshBinaryPath, err := ex.LookPath("ssh")
   346→	if err != nil {
   347→		return xerrors.Errorf("Failed to lookup ssh binary path. err: %w", err)
   348→	}
   349→
   350→	sshConfigCmd := buildSSHConfigCmd(sshBinaryPath, c)
   351→	logging.Log.Debugf("Executing... %s", strings.Replace(sshConfigCmd, "\n", "", -1))
   352→	configResult := localExec(*c, sshConfigCmd, noSudo)
   353→	if !configResult.isSuccess() {
   354→		return xerrors.Errorf("Failed to print SSH configuration. err: %w", configResult.Error)
   355→	}
   356→	sshConfig := parseSSHConfiguration(configResult.Stdout)
   357→	c.User = sshConfig.user
   358→	logging.Log.Debugf("Setting SSH User:%s for Server:%s ...", sshConfig.user, c.GetServerName())
   359→	c.Port = sshConfig.port
   360→	logging.Log.Debugf("Setting SSH Port:%s for Server:%s ...", sshConfig.port, c.GetServerName())
   361→	if c.User == "" || c.Port == "" {
   362→		return xerrors.New("Failed to find User or Port setting. Please check the User or Port settings for SSH")
   363→	}
   364→
   365→	if sshConfig.strictHostKeyChecking == "false" {
   366→		return nil
   367→	}
   368→	if sshConfig.proxyCommand != "" || sshConfig.proxyJump != "" {
   369→		logging.Log.Debug("known_host check under Proxy is not yet implemented")
   370→		return nil
   371→	}
   372→
   373→	logging.Log.Debugf("Checking if the host's public key is in known_hosts...")
   374→	knownHostsPaths := []string{}
   375→	for _, knownHost := range append(sshConfig.userKnownHosts, sshConfig.globalKnownHosts...) {
   376→		if knownHost != "" && knownHost != "/dev/null" {
   377→			knownHostsPaths = append(knownHostsPaths, knownHost)
   378→		}
   379→	}
   380→	if len(knownHostsPaths) == 0 {
   381→		return xerrors.New("Failed to find any known_hosts to use. Please check the UserKnownHostsFile and GlobalKnownHostsFile settings for SSH")
   382→	}
   383→
   384→	sshKeyscanBinaryPath, err := ex.LookPath("ssh-keyscan")
   385→	if err != nil {
   386→		return xerrors.Errorf("Failed to lookup ssh-keyscan binary path. err: %w", err)
   387→	}
   388→	sshScanCmd := strings.Join([]string{sshKeyscanBinaryPath, "-p", c.Port, sshConfig.hostname}, " ")
   389→	r := localExec(*c, sshScanCmd, noSudo)
   390→	if !r.isSuccess() {
   391→		return xerrors.Errorf("Failed to ssh-keyscan. cmd: %s, err: %w", sshScanCmd, r.Error)
   392→	}
   393→	serverKeys := parseSSHScan(r.Stdout)
   394→
   395→	sshKeygenBinaryPath, err := ex.LookPath("ssh-keygen")
   396→	if err != nil {
   397→		return xerrors.Errorf("Failed to lookup ssh-keygen binary path. err: %w", err)
   398→	}
   399→	for _, knownHosts := range knownHostsPaths {
   400→		var hostname string
   401→		if sshConfig.hostKeyAlias != "" {
   402→			hostname = sshConfig.hostKeyAlias
   403→		} else {
   404→			if c.Port != "" && c.Port != "22" {
   405→				hostname = fmt.Sprintf("\"[%s]:%s\"", sshConfig.hostname, c.Port)
   406→			} else {
   407→				hostname = sshConfig.hostname
   408→			}
   409→		}
   410→		cmd := fmt.Sprintf("%s -F %s -f %s", sshKeygenBinaryPath, hostname, knownHosts)
   411→		logging.Log.Debugf("Executing... %s", strings.Replace(cmd, "\n", "", -1))
   412→		if r := localExec(*c, cmd, noSudo); r.isSuccess() {
   413→			keyType, clientKey, err := parseSSHKeygen(r.Stdout)
   414→			if err != nil {
   415→				return xerrors.Errorf("Failed to parse ssh-keygen result. stdout: %s, err: %w", r.Stdout, r.Error)
   416→			}
   417→			if serverKey, ok := serverKeys[keyType]; ok && serverKey == clientKey {
   418→				return nil
   419→			}
   420→			return xerrors.Errorf("Failed to find the server key that matches the key registered in the client. The server key may have been changed. Please exec `$ %s` and `$ %s` or `$ %s`",
   421→				fmt.Sprintf("%s -R %s -f %s", sshKeygenBinaryPath, hostname, knownHosts),
   422→				strings.Join(buildSSHBaseCmd(sshBinaryPath, c, nil), " "),
   423→				buildSSHKeyScanCmd(sshKeyscanBinaryPath, c.Port, knownHostsPaths[0], sshConfig))
   424→		}
   425→	}
   426→	return xerrors.Errorf("Failed to find the host in known_hosts. Please exec `$ %s` or `$ %s`",
   427→		strings.Join(buildSSHBaseCmd(sshBinaryPath, c, nil), " "),
   428→		buildSSHKeyScanCmd(sshKeyscanBinaryPath, c.Port, knownHostsPaths[0], sshConfig))
   429→}
   430→
   431→func buildSSHBaseCmd(sshBinaryPath string, c *config.ServerInfo, options []string) []string {
   432→	cmd := []string{sshBinaryPath}
   433→	if len(options) > 0 {
   434→		cmd = append(cmd, options...)
   435→	}
   436→	if c.SSHConfigPath != "" {
   437→		cmd = append(cmd, "-F", c.SSHConfigPath)
   438→	}
   439→	if c.KeyPath != "" {
   440→		cmd = append(cmd, "-i", c.KeyPath)
   441→	}
   442→	if c.Port != "" {
   443→		cmd = append(cmd, "-p", c.Port)
   444→	}
   445→	if c.User != "" {
   446→		cmd = append(cmd, "-l", c.User)
   447→	}
   448→	if len(c.JumpServer) > 0 {
   449→		cmd = append(cmd, "-J", strings.Join(c.JumpServer, ","))
   450→	}
   451→	cmd = append(cmd, c.Host)
   452→	return cmd
   453→}
   454→
   455→func buildSSHConfigCmd(sshBinaryPath string, c *config.ServerInfo) string {
   456→	return strings.Join(buildSSHBaseCmd(sshBinaryPath, c, []string{"-G"}), " ")
   457→}
   458→
   459→func buildSSHKeyScanCmd(sshKeyscanBinaryPath, port, knownHosts string, sshConfig sshConfiguration) string {
   460→	cmd := []string{sshKeyscanBinaryPath}
   461→	if sshConfig.hashKnownHosts == "yes" {
   462→		cmd = append(cmd, "-H")
   463→	}
   464→	if port != "" {
   465→		cmd = append(cmd, "-p", port)
   466→	}
   467→	return strings.Join(append(cmd, sshConfig.hostname, ">>", knownHosts), " ")
   468→}
