   546→func (s Scanner) detectContainerOSes(hosts []osTypeInterface) (actives, inactives []osTypeInterface) {
   547→	logging.Log.Info("Detecting OS of containers... ")
   548→	osTypesChan := make(chan []osTypeInterface, len(hosts))
   549→	defer close(osTypesChan)
   550→	for _, host := range hosts {
   551→		go func(h osTypeInterface) {
   552→			defer func() {
   553→				if p := recover(); p != nil {
   554→					logging.Log.Debugf("Panic: %s on %s",
   555→						p, h.getServerInfo().GetServerName())
   556→				}
   557→			}()
   558→			osTypesChan <- s.detectContainerOSesOnServer(h)
   559→		}(host)
   560→	}
   561→
   562→	timeout := time.After(time.Duration(s.TimeoutSec) * time.Second)
   563→	for i := 0; i < len(hosts); i++ {
   564→		select {
   565→		case res := <-osTypesChan:
   566→			for _, osi := range res {
   567→				sinfo := osi.getServerInfo()
   568→				if 0 < len(osi.getErrs()) {
   569→					inactives = append(inactives, osi)
   570→					logging.Log.Errorf("Failed: %s err: %+v", sinfo.ServerName, osi.getErrs())
   571→					continue
   572→				}
   573→				actives = append(actives, osi)
   574→				logging.Log.Infof("Detected: %s@%s: %s",
   575→					sinfo.Container.Name, sinfo.ServerName, osi.getDistro())
   576→			}
   577→		case <-timeout:
   578→			logging.Log.Error("Some containers timed out")
   579→		}
   580→	}
   581→	return
   582→}
   583→
   584→func (s Scanner) detectContainerOSesOnServer(containerHost osTypeInterface) (oses []osTypeInterface) {
   585→	containerHostInfo := containerHost.getServerInfo()
   586→	if len(containerHostInfo.ContainersIncluded) == 0 {
   587→		return
   588→	}
   589→
   590→	running, err := containerHost.runningContainers()
   591→	if err != nil {
   592→		containerHost.setErrs([]error{xerrors.Errorf(
   593→			"Failed to get running containers on %s. err: %w",
   594→			containerHost.getServerInfo().ServerName, err)})
   595→		return append(oses, containerHost)
   596→	}
   597→
   598→	if containerHostInfo.ContainersIncluded[0] == "${running}" {
   599→		for _, containerInfo := range running {
   600→			found := false
   601→			for _, ex := range containerHost.getServerInfo().ContainersExcluded {
   602→				if containerInfo.Name == ex || containerInfo.ContainerID == ex {
   603→					found = true
   604→				}
   605→			}
   606→			if found {
   607→				continue
   608→			}
   609→
   610→			copied := containerHostInfo
   611→			copied.SetContainer(config.Container{
   612→				ContainerID: containerInfo.ContainerID,
   613→				Name:        containerInfo.Name,
   614→				Image:       containerInfo.Image,
   615→			})
   616→			os := s.detectOS(copied)
   617→			oses = append(oses, os)
   618→		}
   619→		return oses
   620→	}
   621→
   622→	exitedContainers, err := containerHost.exitedContainers()
   623→	if err != nil {
   624→		containerHost.setErrs([]error{xerrors.Errorf(
   625→			"Failed to get exited containers on %s. err: %w",
   626→			containerHost.getServerInfo().ServerName, err)})
   627→		return append(oses, containerHost)
   628→	}
   629→
   630→	var exited, unknown []string
   631→	for _, container := range containerHostInfo.ContainersIncluded {
   632→		found := false
   633→		for _, c := range running {
   634→			if c.ContainerID == container || c.Name == container {
   635→				copied := containerHostInfo
   636→				copied.SetContainer(c)
   637→				os := s.detectOS(copied)
   638→				oses = append(oses, os)
   639→				found = true
   640→				break
   641→			}
   642→		}
   643→
   644→		if !found {
   645→			foundInExitedContainers := false
   646→			for _, c := range exitedContainers {
   647→				if c.ContainerID == container || c.Name == container {
   648→					exited = append(exited, container)
   649→					foundInExitedContainers = true
   650→					break
   651→				}
   652→			}
   653→			if !foundInExitedContainers {
   654→				unknown = append(unknown, container)
   655→			}
   656→		}
   657→	}
   658→	if 0 < len(exited) || 0 < len(unknown) {
   659→		containerHost.setErrs([]error{xerrors.Errorf(
   660→			"Some containers on %s are exited or unknown. exited: %s, unknown: %s",
   661→			containerHost.getServerInfo().ServerName, exited, unknown)})
   662→		return append(oses, containerHost)
   663→	}
   664→	return oses
   665→}
   666→
   667→func (s Scanner) detectOS(c config.ServerInfo) osTypeInterface {
   668→	if itsMe, osType, _ := detectPseudo(c); itsMe {
   669→		return osType
   670→	}
   671→
   672→	if itsMe, osType, fatalErr := s.detectDebianWithRetry(c); fatalErr != nil {
   673→		osType.setErrs([]error{xerrors.Errorf("Failed to detect OS: %w", fatalErr)})
   674→		return osType
   675→	} else if itsMe {
   676→		logging.Log.Debugf("Debian based Linux. Host: %s:%s", c.Host, c.Port)
   677→		return osType
   678→	}
   679→
   680→	if itsMe, osType := detectRedhat(c); itsMe {
   681→		logging.Log.Debugf("Redhat based Linux. Host: %s:%s", c.Host, c.Port)
   682→		return osType
   683→	}
   684→
   685→	if itsMe, osType := detectSUSE(c); itsMe {
   686→		logging.Log.Debugf("SUSE Linux. Host: %s:%s", c.Host, c.Port)
   687→		return osType
   688→	}
   689→
   690→	if itsMe, osType := detectFreebsd(c); itsMe {
   691→		logging.Log.Debugf("FreeBSD. Host: %s:%s", c.Host, c.Port)
   692→		return osType
   693→	}
   694→
   695→	if itsMe, osType := detectAlpine(c); itsMe {
   696→		logging.Log.Debugf("Alpine. Host: %s:%s", c.Host, c.Port)
   697→		return osType
   698→	}
   699→
   700→	osType := &unknown{base{ServerInfo: c}}
   701→	osType.setErrs([]error{xerrors.New("Unknown OS Type")})
   702→	return osType
   703→}
   704→
   705→// Retry as it may stall on the first SSH connection
   706→// https://github.com/future-architect/vuls/pull/753
   707→func (s Scanner) detectDebianWithRetry(c config.ServerInfo) (itsMe bool, deb osTypeInterface, err error) {
   708→	type Response struct {
   709→		itsMe bool
   710→		deb   osTypeInterface
   711→		err   error
   712→	}
   713→	resChan := make(chan Response, 1)
   714→	go func(c config.ServerInfo) {
   715→		itsMe, osType, fatalErr := detectDebian(c)
   716→		resChan <- Response{itsMe, osType, fatalErr}
   717→	}(c)
   718→
   719→	timeout := time.After(time.Duration(3) * time.Second)
   720→	select {
   721→	case res := <-resChan:
   722→		return res.itsMe, res.deb, res.err
   723→	case <-timeout:
   724→		time.Sleep(100 * time.Millisecond)
   725→		return detectDebian(c)
   726→	}
   727→}
   728→
   729→// checkScanModes checks scan mode
   730→func (s Scanner) checkScanModes() error {
   731→	for _, s := range servers {
   732→		if err := s.checkScanMode(); err != nil {
   733→			return xerrors.Errorf("servers.%s.scanMode err: %w",
   734→				s.getServerInfo().GetServerName(), err)
   735→		}
   736→	}
   737→	return nil
   738→}
   739→
   740→// checkDependencies checks dependencies are installed on target servers.
   741→func (s Scanner) checkDependencies() {
   742→	parallelExec(func(o osTypeInterface) error {
   743→		return o.checkDeps()
   744→	}, s.TimeoutSec)
   745→	return
   746→}
   747→
   748→// checkIfSudoNoPasswd checks whether vuls can sudo with nopassword via SSH
   749→func (s Scanner) checkIfSudoNoPasswd() {
   750→	parallelExec(func(o osTypeInterface) error {
   751→		return o.checkIfSudoNoPasswd()
   752→	}, s.TimeoutSec)
   753→	return
   754→}
   755→
   756→// detectPlatform detects the platform of each servers.
   757→func (s Scanner) detectPlatform() {
   758→	parallelExec(func(o osTypeInterface) error {
   759→		o.detectPlatform()
   760→		// Logging only if platform can not be specified
   761→		return nil
   762→	}, s.TimeoutSec)
   763→
   764→	for i, s := range servers {
   765→		if s.getServerInfo().IsContainer() {
   766→			logging.Log.Infof("(%d/%d) %s on %s is running on %s",
   767→				i+1, len(servers),
   768→				s.getServerInfo().Container.Name,
   769→				s.getServerInfo().ServerName,
   770→				s.getPlatform().Name,
   771→			)
   772→
   773→		} else {
   774→			logging.Log.Infof("(%d/%d) %s is running on %s",
   775→				i+1, len(servers),
   776→				s.getServerInfo().ServerName,
   777→				s.getPlatform().Name,
   778→			)
   779→		}
   780→	}
   781→	return
   782→}
   783→
   784→// detectIPS detects the IPS of each servers.
   785→func (s Scanner) detectIPS() {
   786→	parallelExec(func(o osTypeInterface) error {
   787→		o.detectIPS()
   788→		// Logging only if IPS can not be specified
   789→		return nil
   790→	}, s.TimeoutSec)
   791→
   792→	for i, s := range servers {
   793→		if !s.getServerInfo().IsContainer() {
   794→			logging.Log.Infof("(%d/%d) %s has %d IPS integration",
   795→				i+1, len(servers),
   796→				s.getServerInfo().ServerName,
   797→				len(s.getServerInfo().IPSIdentifiers),
   798→			)
   799→		}
   800→	}
   801→}
   802→
   803→// execScan scan
   804→func (s Scanner) execScan() error {
   805→	if len(servers) == 0 {
   806→		return xerrors.New("No server defined. Check the configuration")
   807→	}
   808→
   809→	if err := s.setupChangelogCache(); err != nil {
   810→		return err
   811→	}
   812→	defer func() {
   813→		if cache.DB != nil {
   814→			cache.DB.Close()
   815→		}
   816→	}()
   817→
   818→	scannedAt := time.Now()
   819→	dir, err := EnsureResultDir(s.ResultsDir, scannedAt)
   820→	if err != nil {
   821→		return err
   822→	}
   823→
   824→	results, err := s.getScanResults(scannedAt)
   825→	if err != nil {
   826→		return err
   827→	}
   828→
   829→	for i, r := range results {
   830→		if server, ok := s.Targets[r.ServerName]; ok {
   831→			results[i] = r.ClearFields(server.IgnoredJSONKeys)
   832→		}
   833→	}
   834→
   835→	return writeScanResults(dir, results)
   836→}
   837→
   838→func (s Scanner) setupChangelogCache() error {
   839→	needToSetupCache := false
   840→	for _, s := range servers {
   841→		switch s.getDistro().Family {
   842→		case constant.Raspbian:
   843→			needToSetupCache = true
   844→			break
   845→		case constant.Ubuntu, constant.Debian:
   846→			//TODO changelog cache for RedHat, Oracle, Amazon, CentOS is not implemented yet.
   847→			if s.getServerInfo().Mode.IsDeep() {
   848→				needToSetupCache = true
   849→			}
   850→			break
   851→		}
   852→	}
   853→	if needToSetupCache {
   854→		if err := cache.SetupBolt(s.CacheDBPath, logging.Log); err != nil {
   855→			return err
   856→		}
   857→	}
   858→	return nil
   859→}
   860→
   861→// getScanResults returns ScanResults
   862→func (s Scanner) getScanResults(scannedAt time.Time) (results models.ScanResults, err error) {
   863→	parallelExec(func(o osTypeInterface) (err error) {
   864→		if o.getServerInfo().Module.IsScanOSPkg() {
   865→			if err = o.preCure(); err != nil {
   866→				return err
   867→			}
   868→			if err = o.scanPackages(); err != nil {
   869→				return err
   870→			}
   871→			if err = o.postScan(); err != nil {
   872→				return err
   873→			}
   874→		}
   875→		if o.getServerInfo().Module.IsScanPort() {
   876→			if err = o.scanPorts(); err != nil {
   877→				// continue scanning
   878→				logging.Log.Warnf("Failed to scan Ports: %+v", err)
   879→			}
   880→		}
   881→		if o.getServerInfo().Module.IsScanWordPress() {
   882→			if err = o.scanWordPress(); err != nil {
   883→				return xerrors.Errorf("Failed to scan WordPress: %w", err)
   884→			}
   885→		}
   886→		if o.getServerInfo().Module.IsScanLockFile() {
   887→			if err = o.scanLibraries(); err != nil {
   888→				return xerrors.Errorf("Failed to scan Library: %w", err)
   889→			}
   890→		}
   891→		return nil
   892→	}, s.ScanTimeoutSec)
   893→
   894→	hostname, _ := os.Hostname()
   895→	ipv4s, ipv6s, err := util.IP()
   896→	if err != nil {
   897→		logging.Log.Warnf("Failed to get scannedIPs. err: %+v", err)
   898→	}
   899→
   900→	for _, s := range append(servers, errServers...) {
   901→		r := s.convertToModel()
   902→		r.CheckEOL()
   903→		r.ScannedAt = scannedAt
   904→		r.ScannedVersion = config.Version
   905→		r.ScannedRevision = config.Revision
   906→		r.ScannedBy = hostname
   907→		r.ScannedIPv4Addrs = ipv4s
   908→		r.ScannedIPv6Addrs = ipv6s
   909→		r.Config.Scan = config.Conf
   910→		results = append(results, r)
   911→
   912→		if 0 < len(r.Warnings) {
   913→			logging.Log.Warnf("Some warnings occurred during scanning on %s. Please fix the warnings to get a useful information. Execute configtest subcommand before scanning to know the cause of the warnings. warnings: %v",
   914→				r.ServerName, r.Warnings)
   915→		}
   916→	}
   917→	return results, nil
   918→}
   919→

