   249→// initServers detect the kind of OS distribution of target servers
   250→func (s Scanner) initServers() error {
   251→	hosts, errHosts := s.detectServerOSes()
   252→	if len(hosts) == 0 {
   253→		return xerrors.New("No scannable host OS")
   254→	}
   255→
   256→	// to generate random color for logging
   257→	rand.Seed(time.Now().UnixNano())
   258→	for _, srv := range hosts {
   259→		srv.setLogger(logging.NewCustomLogger(s.Debug, s.Quiet, s.LogToFile, s.LogDir, config.Colors[rand.Intn(len(config.Colors))], srv.getServerInfo().GetServerName()))
   260→	}
   261→
   262→	containers, errContainers := s.detectContainerOSes(hosts)
   263→	for _, srv := range containers {
   264→		srv.setLogger(logging.NewCustomLogger(s.Debug, s.Quiet, s.LogToFile, s.LogDir, config.Colors[rand.Intn(len(config.Colors))], srv.getServerInfo().GetServerName()))
   265→	}
   266→
   267→	// set to pkg global variable
   268→	for _, host := range hosts {
   269→		if !host.getServerInfo().ContainersOnly {
   270→			servers = append(servers, host)
   271→		}
   272→	}
   273→	servers = append(servers, containers...)
   274→	errServers = append(errHosts, errContainers...)
   275→
   276→	if len(servers) == 0 {
   277→		return xerrors.New("No scannable servers")
   278→	}
   279→	return nil
   280→}
