   470→type sshConfiguration struct {
   471→	hostname              string
   472→	hostKeyAlias          string
   473→	hashKnownHosts        string
   474→	user                  string
   475→	port                  string
   476→	strictHostKeyChecking string
   477→	globalKnownHosts      []string
   478→	userKnownHosts        []string
   479→	proxyCommand          string
   480→	proxyJump             string
   481→}
   482→
   483→func parseSSHConfiguration(stdout string) sshConfiguration {
   484→	sshConfig := sshConfiguration{}
   485→	for _, line := range strings.Split(stdout, "\n") {
   486→		switch {
   487→		case strings.HasPrefix(line, "user "):
   488→			sshConfig.user = strings.TrimPrefix(line, "user ")
   489→		case strings.HasPrefix(line, "hostname "):
   490→			sshConfig.hostname = strings.TrimPrefix(line, "hostname ")
   491→		case strings.HasPrefix(line, "hostkeyalias "):
   492→			sshConfig.hostKeyAlias = strings.TrimPrefix(line, "hostkeyalias ")
   493→		case strings.HasPrefix(line, "hashknownhosts "):
   494→			sshConfig.hashKnownHosts = strings.TrimPrefix(line, "hashknownhosts ")
   495→		case strings.HasPrefix(line, "port "):
   496→			sshConfig.port = strings.TrimPrefix(line, "port ")
   497→		case strings.HasPrefix(line, "stricthostkeychecking "):
   498→			sshConfig.strictHostKeyChecking = strings.TrimPrefix(line, "stricthostkeychecking ")
   499→		case strings.HasPrefix(line, "globalknownhostsfile "):
   500→			sshConfig.globalKnownHosts = strings.Split(strings.TrimPrefix(line, "globalknownhostsfile "), " ")
   501→		case strings.HasPrefix(line, "userknownhostsfile "):
   502→			sshConfig.userKnownHosts = strings.Split(strings.TrimPrefix(line, "userknownhostsfile "), " ")
   503→		case strings.HasPrefix(line, "proxycommand "):
   504→			sshConfig.proxyCommand = strings.TrimPrefix(line, "proxycommand ")
   505→		case strings.HasPrefix(line, "proxyjump "):
   506→			sshConfig.proxyJump = strings.TrimPrefix(line, "proxyjump ")
   507→		}
   508→	}
   509→	return sshConfig
   510→}
   511→
   512→func parseSSHScan(stdout string) map[string]string {
   513→	keys := map[string]string{}
   514→	for _, line := range strings.Split(stdout, "\n") {
   515→		if line == "" || strings.HasPrefix(line, "# ") {
   516→			continue
   517→		}
   518→		if ss := strings.Split(line, " "); len(ss) == 3 {
   519→			keys[ss[1]] = ss[2]
   520→		}
   521→	}
   522→	return keys
   523→}
   524→
   525→func parseSSHKeygen(stdout string) (string, string, error) {
   526→	for _, line := range strings.Split(stdout, "\n") {
   527→		if line == "" || strings.HasPrefix(line, "# ") {
   528→			continue
   529→		}
   530→
   531→		// HashKnownHosts yes
   532→		if strings.HasPrefix(line, "|1|") {
   533→			ss := strings.Split(line, "|")
   534→			if ss := strings.Split(ss[len(ss)-1], " "); len(ss) == 3 {
   535→				return ss[1], ss[2], nil
   536→			}
   537→		} else {
   538→			if ss := strings.Split(line, " "); len(ss) == 3 {
   539→				return ss[1], ss[2], nil
   540→			}
   541→		}
   542→	}
   543→	return "", "", xerrors.New("Failed to parse ssh-keygen result. err: public key not found")
   544→}
