   546→func (s Scanner) detectContainerOSes(hosts []osTypeInterface) (actives, inactives []osTypeInterface) {
   547→	logging.Log.Info("Detecting OS of containers... ")
   548→	osTypesChan := make(chan []osTypeInterface, len(hosts))
   549→	defer close(osTypesChan)
   550→	for _, host := range hosts {
   551→		go func(h osTypeInterface) {
   552→			defer func() {
   553→				if p := recover(); p != nil {
   554→					logging.Log.Debugf("Panic: %s on %s",
   555→						p, h.getServerInfo().GetServerName())
   556→				}
   557→			}()
   558→			osTypesChan <- s.detectContainerOSesOnServer(h)
   559→		}(host)
   560→	}
   561→
   562→	timeout := time.After(time.Duration(s.TimeoutSec) * time.Second)
   563→	for i := 0; i < len(hosts); i++ {
   564→		select {
   565→		case res := <-osTypesChan:
   566→			for _, osi := range res {
   567→				sinfo := osi.getServerInfo()
   568→				if 0 < len(osi.getErrs()) {
   569→					inactives = append(inactives, osi)
   570→					logging.Log.Errorf("Failed: %s err: %+v", sinfo.ServerName, osi.getErrs())
   571→					continue
   572→				}
   573→				actives = append(actives, osi)
   574→				logging.Log.Infof("Detected: %s@%s: %s",
   575→					sinfo.Container.Name, sinfo.ServerName, osi.getDistro())
   576→			}
   577→		case <-timeout:
   578→			logging.Log.Error("Some containers timed out")
   579→		}
