   584→func (s Scanner) detectContainerOSesOnServer(containerHost osTypeInterface) (oses []osTypeInterface) {
   585→	containerHostInfo := containerHost.getServerInfo()
   586→	if len(containerHostInfo.ContainersIncluded) == 0 {
   587→		return
   588→	}
   589→
   590→	running, err := containerHost.runningContainers()
   591→	if err != nil {
   592→		containerHost.setErrs([]error{xerrors.Errorf(
   593→			"Failed to get running containers on %s. err: %w",
   594→			containerHost.getServerInfo().ServerName, err)})
   595→		return append(oses, containerHost)
   596→	}
   597→
   598→	if containerHostInfo.ContainersIncluded[0] == "${running}" {
   599→		for _, containerInfo := range running {
   600→			found := false
   601→			for _, ex := range containerHost.getServerInfo().ContainersExcluded {
   602→				if containerInfo.Name == ex || containerInfo.ContainerID == ex {
   603→					found = true
   604→				}
   605→			}
   606→			if found {
   607→				continue
   608→			}
   609→
   610→			copied := containerHostInfo
   611→			copied.SetContainer(config.Container{
   612→				ContainerID: containerInfo.ContainerID,
   613→				Name:        containerInfo.Name,
   614→				Image:       containerInfo.Image,
   615→			})
   616→			os := s.detectOS(copied)
   617→			oses = append(oses, os)
   618→		}
   619→		return oses
   620→	}
   621→
   622→	exitedContainers, err := containerHost.exitedContainers()
   623→	if err != nil {
   624→		containerHost.setErrs([]error{xerrors.Errorf(
   625→			"Failed to get exited containers on %s. err: %w",
   626→			containerHost.getServerInfo().ServerName, err)})
   627→		return append(oses, containerHost)
   628→	}
   629→
   630→	var exited, unknown []string
   631→	for _, container := range containerHostInfo.ContainersIncluded {
   632→		found := false
   633→		for _, c := range running {
   634→			if c.ContainerID == container || c.Name == container {
   635→				copied := containerHostInfo
   636→				copied.SetContainer(c)
   637→				os := s.detectOS(copied)
   638→				oses = append(oses, os)
   639→				found = true
   640→				break
   641→			}
   642→		}
   643→
   644→		if !found {
   645→			foundInExitedContainers := false
   646→			for _, c := range exitedContainers {
   647→				if c.ContainerID == container || c.Name == container {
   648→					exited = append(exited, container)
   649→					foundInExitedContainers = true
   650→					break
   651→				}
   652→			}
   653→			if !foundInExitedContainers {
   654→				unknown = append(unknown, container)
   655→			}
   656→		}
   657→	}
   658→	if 0 < len(exited) || 0 < len(unknown) {
   659→		containerHost.setErrs([]error{xerrors.Errorf(
   660→			"Some containers on %s are exited or unknown. exited: %s, unknown: %s",
   661→			containerHost.getServerInfo().ServerName, exited, unknown)})
   662→		return append(oses, containerHost)
   663→	}
   664→	return oses
   665→}
