   705→// Retry as it may stall on the first SSH connection
   706→// https://github.com/future-architect/vuls/pull/753
   707→func (s Scanner) detectDebianWithRetry(c config.ServerInfo) (itsMe bool, deb osTypeInterface, err error) {
   708→	type Response struct {
   709→		itsMe bool
   710→		deb   osTypeInterface
   711→		err   error
   712→	}
   713→	resChan := make(chan Response, 1)
   714→	go func(c config.ServerInfo) {
   715→		itsMe, osType, fatalErr := detectDebian(c)
   716→		resChan <- Response{itsMe, osType, fatalErr}
   717→	}(c)
   718→
   719→	timeout := time.After(time.Duration(3) * time.Second)
   720→	select {
   721→	case res := <-resChan:
   722→		return res.itsMe, res.deb, res.err
   723→	case <-timeout:
   724→		time.Sleep(100 * time.Millisecond)
   725→		return detectDebian(c)
   726→	}
   727→}
