   838→func (s Scanner) setupChangelogCache() error {
   839→	needToSetupCache := false
   840→	for _, s := range servers {
   841→		switch s.getDistro().Family {
   842→		case constant.Raspbian:
   843→			needToSetupCache = true
   844→			break
   845→		case constant.Ubuntu, constant.Debian:
   846→			//TODO changelog cache for RedHat, Oracle, Amazon, CentOS is not implemented yet.
   847→			if s.getServerInfo().Mode.IsDeep() {
   848→				needToSetupCache = true
   849→			}
   850→			break
   851→		}
   852→	}
   853→	if needToSetupCache {
   854→		if err := cache.SetupBolt(s.CacheDBPath, logging.Log); err != nil {
   855→			return err
   856→		}
   857→	}
