		name       string
		lockFile   string
		ecosystem  string
	}{
		{"Node.js (npm)", "package-lock.json", "node"},
		{"Node.js (yarn)", "yarn.lock", "node"},
		{"Python (pip)", "requirements.txt", "python"},
		{"Python (Poetry)", "poetry.lock", "python"},
		{"Ruby", "Gemfile.lock", "ruby"},
		{"Rust", "Cargo.lock", "rust"},
		{"PHP", "composer.lock", "php"},
		{"Java", "pom.xml", "java"},
		{"Go", "go.mod", "gomod"},
		{".NET (NuGet)", "packages.lock.json", ".net"},
		{"PNPM", "pnpm-lock.yaml", "node"}, // Expected to fail
	}

	for _, tc := range requiredEcosystems {
		if ecosystem, ok := models.LibraryMap[tc.lockFile]; ok {
			if ecosystem != tc.ecosystem {
				t.Errorf("%s: expected ecosystem %s, got %s", tc.name, tc.ecosystem, ecosystem)
