// Issue 2: Missing package ecosystems for PNPM
func testMissingPnpmInLibraryMap(t *testing.T) {
	t.Logf("Issue 2: Missing PNPM Package Ecosystem Support")
	t.Logf("Testing: PNPM lockfile detection and analysis")
	t.Logf("")

	// Test 1: Check if pnpm-lock.yaml is in LibraryMap
	pnpmSupported := false
	for filename := range models.LibraryMap {
		if filename == "pnpm-lock.yaml" {
			pnpmSupported = true
			break
		}
	}

	if pnpmSupported {
		t.Logf("✓ PNPM appears to be in LibraryMap")
		t.Logf("  This indicates the bug may have been fixed")
	} else {
		t.Errorf("✗ CRITICAL: PNPM (pnpm-lock.yaml) is NOT in LibraryMap")
		t.Logf("  This is a regression test failure - bug is confirmed")
		t.Logf("")
		t.Logf("Supported ecosystems:")
		for filename, ecosystem := range models.LibraryMap {
			t.Logf("  - %s -> %s", filename, ecosystem)
		}
	}

	// Test 2: Try to analyze a PNPM lockfile
	t.Logf("")
	t.Logf("Attempting to analyze PNPM lockfile...")
	pnpmLockContent := []byte(`lockfileVersion: 5.4
requires: true
packages:
  'lodash@4.17.21':
    version: 4.17.21
    resolved: 'https://registry.npmjs.org/lodash/-/lodash-4.17.21.tgz'`)

	libFilemap := map[string]scanner.LibFile{
		"pnpm-lock.yaml": {
			Contents: pnpmLockContent,
			Filemode: 0644,
		},
	}

	libraryScanners, err := scanner.AnalyzeLibraries(context.Background(), libFilemap, false)
	if err != nil {
		// May fail because PNPM is not supported
		t.Logf("Got error analyzing PNPM (expected if PNPM not supported): %v", err)
	} else if len(libraryScanners) == 0 {
		t.Errorf("✗ PNPM lockfile was analyzed but returned zero results")
		t.Logf("  PNPM ecosystem is not recognized by analyzer")
	} else {
		// Check if results look like PNPM packages
		t.Logf("✓ PNPM lockfile analysis returned %d scanner(s)", len(libraryScanners))
		for _, scanner := range libraryScanners {
			t.Logf("  Type: %s, Libraries: %d", scanner.Type, len(scanner.Libs))
		}
	}
}

