// testAnalyzerScopeControl verifies the analyzer scope is incomplete
// Issue 3: Incomplete scan scope control - non-library analyzers may run
func testAnalyzerScopeControl(t *testing.T) {
	t.Logf("Issue 3: Incomplete Scan Scope Control")
	t.Logf("File: scanner/base.go, Lines 665-718 (AnalyzeLibraries function)")
	t.Logf("")

	// Create test content - YAML file that should NOT be analyzed
	yamlContent := []byte(`name: test-config
version: 1.0
configuration:
  secret: my-secret-key
`)

	// Create test content - JSON file that could contain secrets
	jsonContent := []byte(`{
  "password": "admin123",
  "api_key": "sk_live_ABC123"
}`)

	testCases := []struct {
		name     string
		filename string
		content  []byte
	}{
		{"YAML config file", "config.yaml", yamlContent},
		{"JSON config file", "secrets.json", jsonContent},
	}

	for _, tc := range testCases {
		t.Logf("")
		t.Logf("Test case: %s", tc.name)

		libFilemap := map[string]scanner.LibFile{
			tc.filename: {
				Contents: tc.content,
				Filemode: 0644,
			},
		}

		// Try to analyze - if scope control is complete, this should return
		// no results or error (these file types should be disabled)
		libraryScanners, err := scanner.AnalyzeLibraries(context.Background(), libFilemap, false)

		if err != nil {
			t.Logf("  Analysis error (may be expected): %v", err)
		} else if len(libraryScanners) == 0 {
			t.Logf("  ✓ No libraries detected - scope control working")
		} else {
			t.Errorf("  ✗ Detected %d scanners for %s - scope control incomplete", len(libraryScanners), tc.filename)
			for _, ls := range libraryScanners {
				t.Logf("    Scanner type: %s, libraries: %d", ls.Type, len(ls.Libs))
			}
		}
	}

	t.Logf("")
	t.Logf("Analysis: Checking if non-library analyzers are properly disabled")
	basePath := "/app/scanner/base.go"
	content, err := os.ReadFile(basePath)
	if err != nil {
		t.Fatalf("Failed to read %s: %v", basePath, err)
	}

	baseStr := string(content)

