	for _, aType := range disabledTypes {
		if containsString(baseStr, aType) {
			t.Logf("  ✓ %s", aType)
		} else {
			t.Errorf("  ✗ %s NOT FOUND in disabled list", aType)
		}
	}

	t.Logf("")
	t.Logf("Issue: New analyzer types added in newer Trivy versions may not be disabled")
}

